-- ---------------------------------------------------------------------------
-- Recreate triggers that were dropped in Cleanup phase 3.5 so they remain
-- active going forward (their logic is unchanged; only the column types
-- they reference may have shifted from uuid → varchar/text).
-- ---------------------------------------------------------------------------
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger t
    JOIN pg_class c ON c.oid = t.tgrelid
    WHERE c.relname = 'residences' AND t.tgname = 'residences_demand_building_check'
  ) AND EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'residences_check_demand_building') THEN
    EXECUTE $trig$
      CREATE TRIGGER residences_demand_building_check
        BEFORE UPDATE OF building_id
        ON residences
        FOR EACH ROW
        EXECUTE FUNCTION residences_check_demand_building()
    $trig$;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger t
    JOIN pg_class c ON c.oid = t.tgrelid
    WHERE c.relname = 'residences' AND t.tgname = 'residences_demand_assignation_check'
  ) AND EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'residences_check_demand_assignation') THEN
    EXECUTE $trig$
      CREATE TRIGGER residences_demand_assignation_check
        BEFORE UPDATE OF building_id
        ON residences
        FOR EACH ROW
        EXECUTE FUNCTION residences_check_demand_assignation()
    $trig$;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger t
    JOIN pg_class c ON c.oid = t.tgrelid
    WHERE c.relname = 'demands' AND t.tgname = 'demands_residence_building_check'
  ) AND EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'demands_check_residence_building') THEN
    EXECUTE $trig$
      CREATE TRIGGER demands_residence_building_check
        BEFORE INSERT OR UPDATE OF residence_id, building_id
        ON demands
        FOR EACH ROW
        EXECUTE FUNCTION demands_check_residence_building()
    $trig$;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger t
    JOIN pg_class c ON c.oid = t.tgrelid
    WHERE c.relname = 'demands' AND t.tgname = 'demands_assignation_check'
  ) AND EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'demands_check_assignation') THEN
    EXECUTE $trig$
      CREATE TRIGGER demands_assignation_check
        BEFORE INSERT OR UPDATE OF
          assignation_residence_id,
          assignation_building_id,
          building_id
        ON demands
        FOR EACH ROW
        EXECUTE FUNCTION demands_check_assignation()
    $trig$;
  END IF;
END $$;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_trigger t
    JOIN pg_class c ON c.oid = t.tgrelid
    WHERE c.relname = 'invitations' AND t.tgname = 'invitations_residence_building_check'
  ) AND EXISTS (SELECT 1 FROM pg_proc WHERE proname = 'invitations_check_residence_building') THEN
    EXECUTE $trig$
      CREATE TRIGGER invitations_residence_building_check
        BEFORE INSERT OR UPDATE OF residence_id, building_id
        ON invitations
        FOR EACH ROW
        EXECUTE FUNCTION invitations_check_residence_building()
    $trig$;
  END IF;
END $$;
